    float1 dy = ( GetBlur2(vUv + vec2(0,d)) - GetBlur2(vUv-vec2(0,d)) ).y*1024*uTexSize.w;
    vec2 my_uv = vUv - vec2(dx,dy)*0.004;



    ret.y = texture( sampler_pc_main, my_uv).y;
    ret.y += (ret.y - GetBlur1(vUv).y - 0.1)*.1 +0.02;

ret.z = tex2d(sampler_fc_main, vUv - vec2(0,1)*uTexSize.zw).z - 0.004;


vUv = vUvOriginal;
vec2 pixelsize = uTexSize.zw;
float1 conway = texture( sampler_pw_main, vUv + vec2(-1,-1)*pixelsize).x;
       conway += texture( sampler_pw_main, vUv + vec2(0,-1)*pixelsize).x;
       conway += texture( sampler_pw_main, vUv + vec2(1,-1)*pixelsize).x;
       conway += texture( sampler_pw_main, vUv + vec2(-1,0)*pixelsize).x;
